/**
 * Common scalar grammar for GCF.
 * Shared between encoder, decoder, and streaming encoder.
 */
/** Check if a string value must be quoted per Section 2.4. */
export declare function needsQuote(s: string): boolean;
/** Produce a JSON-compatible quoted string. */
export declare function quoteString(s: string): string;
/** Format a JS value as a GCF scalar. delimiter is '|', ',', or 0. */
export declare function formatScalar(v: unknown, delimiter?: number): string;
/** Format a number per Section 2.3 canonical rules. */
export declare function formatNumber(f: number): string;
/** Check if a key is a valid bare key. */
export declare function isBareKey(s: string): boolean;
/** Format a key, quoting if necessary. */
export declare function formatKey(s: string): string;
/** Parse a GCF scalar token per Section 2.1 precedence. */
export declare function parseScalar(s: string, tabularContext: boolean): any;
export declare const MISSING: unique symbol;
export declare const ATTACHMENT: unique symbol;
/** Parse a JSON-compatible quoted string. */
export declare function parseQuotedString(s: string): string;
/** Split a string on a delimiter, respecting quoted strings. */
export declare function splitRespectingQuotes(s: string, delim: string): string[];
/** Split a field declaration like {id,"display name","a,b"}. */
export declare function splitFieldDecl(s: string): string[];
